INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('PSYCHO: Le principe de coherence: une fois qu un prospect dit "oui" a une petite demande, il dira 4x plus facilement "oui" a une grande.', 'Coherence: petit oui → grand oui = 4x', NULL, 'best_practice', 0.90, 'massive_boost_7', 'system'),
('PSYCHO: L effet de dotation: les gens valorisent 2x plus ce qu ils possedent deja. L essai gratuit cree ce sentiment de possession.', 'Effet dotation: essai gratuit = possession', NULL, 'insight', 0.88, 'massive_boost_7', 'system'),
('PSYCHO: Le biais d autorite: citer une etude, un expert ou un media reconnu augmente la credibilite du message de 4x.', 'Biais autorite: citer expert = 4x credibilite', NULL, 'insight', 0.88, 'massive_boost_7', 'system'),
('PSYCHO: Le principe de contraste: montrer le prix eleve d abord puis le prix reduit rend le second beaucoup plus attractif.', 'Contraste prix: cher puis reduit = plus attractif', NULL, 'insight', 0.85, 'massive_boost_7', 'system'),
('PSYCHO: L aversion au regret est 2.5x plus puissante que la motivation au gain. "Ne ratez pas" > "Profitez de".', 'Aversion regret 2.5x > motivation gain', NULL, 'insight', 0.88, 'massive_boost_7', 'system'),
('PSYCHO: Le nombre magique 7 +/- 2: les gens retiennent max 5-9 elements. Limiter les choix, options et infos a ce range.', 'Nombre magique 7: max 5-9 elements', NULL, 'insight', 0.85, 'massive_boost_7', 'system'),
('PSYCHO: La repetition de 3: dire la meme chose 3 fois de 3 manieres differentes maximise la memorisation et la persuasion.', 'Repetition de 3 = memorisation max', NULL, 'insight', 0.82, 'massive_boost_7', 'system'),
('PSYCHO: Le peak-end rule: les gens jugent une experience sur le moment le plus intense + la fin. Soigner la fin de chaque interaction.', 'Peak-end: soigner le pic et la fin', NULL, 'insight', 0.85, 'massive_boost_7', 'system'),
('PSYCHO: L effet de simple exposition: voir une marque 7+ fois cree de la familiarite et de la confiance, meme sans interaction.', 'Simple exposition 7x = confiance', NULL, 'insight', 0.85, 'massive_boost_7', 'system'),
('PSYCHO: Le storytelling active 7 zones du cerveau vs 2 pour les faits. Les histoires persuadent 22x mieux que les arguments logiques.', 'Storytelling: 7 zones cerveau, 22x persuasion', NULL, 'insight', 0.88, 'massive_boost_7', 'system'),
('FIDELISATION: Le cout d acquisition d un nouveau client est 5-7x plus eleve que de retenir un existant. La retention est la priorite.', 'Retention 5-7x moins cher qu acquisition', NULL, 'best_practice', 0.95, 'massive_boost_7', 'system'),
